Yes, you can loop over std::fs::read_dir and process each DirEntry. Example:
let entries = match std::fs::read_dir(".") {
    Ok(ents) => ents,
    Err(e) => return Err(e),
};
for entry in entries {
    let e = entry?;
    println!("File: {:?}", e.path()?);
}

This handles errors per entry.

Here's an example:
let src = std::fs::File::open("data/large.json")?;
let mut reader = BufReader::new(src);
for line in reader.lines() { println!(&line)?; }
If the file is missing, you'll get a `io::Error: cannot open '/...': no such file or directory`. That's the real error.

